import java.util.Arrays;

public int[] rearrangeArrayAroundPivot(int[] nums, int pivot) {
    Arrays.sort(nums, (a, b) -> a < pivot && b >= pivot ? -1 : (a >= pivot && b < pivot ? 1 : 0));
    return nums;
}
```


